// Helper for status colors
export const getStatusColor = (status: ShipmentStatus) => {
  switch (status) {
    case ShipmentStatus.CREATED: return 'bg-gray-100 text-gray-800';
    case ShipmentStatus.SHIPPED: return 'bg-blue-100 text-blue-800';
    case ShipmentStatus.IN_TRANSIT: return 'bg-indigo-100 text-indigo-800';
    case ShipmentStatus.OUT_FOR_DELIVERY: return 'bg-purple-100 text-purple-800';
    case ShipmentStatus.DELIVERED: return 'bg-green-100 text-green-800';
    case ShipmentStatus.EXCEPTION: return 'bg-red-100 text-red-800';
    default: return 'bg-gray-100 text-gray-800';
  }
};

import { LabelGenerationRequest, Shipment, ShipmentStatus } from '../types';
import { MOCK_SENDERS, MOCK_RECIPIENTS } from '../constants';

// This service mocks the interaction with N8N webhooks.
// In a real application, these would be fetch() calls to the URLs in constants.ts

const LOCAL_STORAGE_KEY = 'fedex_app_shipments';

const getStoredShipments = (): Shipment[] => {
  const stored = localStorage.getItem(LOCAL_STORAGE_KEY);
  return stored ? JSON.parse(stored) : [];
};

const saveShipment = (shipment: Shipment) => {
  const current = getStoredShipments();
  localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify([shipment, ...current]));
};

export const n8nService = {
  createLabel: async (request: LabelGenerationRequest): Promise<Shipment> => {
    // Simulate Network Latency
    await new Promise(resolve => setTimeout(resolve, 1500));

    const sender = MOCK_SENDERS.find(s => s.id === request.senderId) || MOCK_SENDERS[0];
    const recipient = MOCK_RECIPIENTS.find(r => r.id === request.recipientId) || MOCK_RECIPIENTS[0];

    // Mock Response from N8N
    const newShipment: Shipment = {
      id: `shp_${Date.now()}`,
      trackingNumber: `1234${Math.floor(Math.random() * 100000000)}`, // Mock Tracking
      reference: request.reference,
      status: ShipmentStatus.CREATED,
      createdDate: new Date().toISOString(),
      sender,
      recipient,
      serviceType: request.serviceType,
      weight: request.weight,
      isReturnLabel: request.options.createReturnLabel,
      notifications: request.options.notifyEmails,
      labelUrl: 'https://dummyimage.com/600x800/fff/000.png&text=FEDEX+LABEL+SAMPLE',
    };

    saveShipment(newShipment);
    return newShipment;
  },

  getHistory: async (): Promise<Shipment[]> => {
    // Simulate Network Latency
    await new Promise(resolve => setTimeout(resolve, 500));
    return getStoredShipments();
  },

  // This would typically trigger a webhook to refresh status
  refreshTracking: async (trackingNumber: string): Promise<ShipmentStatus> => {
    await new Promise(resolve => setTimeout(resolve, 1000));
    const statuses = Object.values(ShipmentStatus);
    const randomStatus = statuses[Math.floor(Math.random() * statuses.length)];
    return randomStatus;
  }
};

import { GoogleGenAI, Type } from "@google/genai";

// Initialize Gemini
// NOTE: API Key must be provided in the environment variable process.env.API_KEY
// The user of this code must ensure the key is valid.

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const parseAddressWithGemini = async (rawText: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Parse the following unstructured address text into a structured JSON object. 
      Text: "${rawText}"

      Extract: Name, Company (if available), Street1, Street2 (if available), City, State, Zip, Country, Phone, Email.
      If a field is missing, leave it as an empty string.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            company: { type: Type.STRING },
            street1: { type: Type.STRING },
            street2: { type: Type.STRING },
            city: { type: Type.STRING },
            state: { type: Type.STRING },
            zip: { type: Type.STRING },
            country: { type: Type.STRING },
            phone: { type: Type.STRING },
            email: { type: Type.STRING },
          },
          required: ["name", "street1", "city", "state", "zip"],
        },
      },
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Parsing Error:", error);
    throw new Error("Failed to parse address with AI");
  }
};

import React, { useState, useEffect } from 'react';
import { X, Truck, Save, Loader2, AlertCircle } from 'lucide-react';
import { Address, LabelGenerationRequest, Shipment } from '../types';
import { MOCK_SENDERS, MOCK_RECIPIENTS, SERVICE_TYPES, INTERNAL_USERS } from '../constants';
import { n8nService } from '../services/n8nService';

interface CreateLabelModalProps {
  isOpen: boolean;
  onClose: () => void;
  preSelectedRecipient?: Address | null;
  onSuccess: (shipment: Shipment) => void;
}

export const CreateLabelModal: React.FC<CreateLabelModalProps> = ({
  isOpen,
  onClose,
  preSelectedRecipient,
  onSuccess,
}) => {
  const [loading, setLoading] = useState(false);
  const [senderId, setSenderId] = useState(MOCK_SENDERS[0].id);
  const [recipientId, setRecipientId] = useState('');
  const [reference, setReference] = useState('');
  const [serviceType, setServiceType] = useState(SERVICE_TYPES[0].value);
  const [weight, setWeight] = useState(1);

  // Options
  const [createReturnLabel, setCreateReturnLabel] = useState(false);
  const [emailLabel, setEmailLabel] = useState(false);
  const [notifyEmails, setNotifyEmails] = useState<string[]>([]);

  const [error, setError] = useState('');

  useEffect(() => {
    if (preSelectedRecipient) {
      setRecipientId(preSelectedRecipient.id);
    } else if (MOCK_RECIPIENTS.length > 0) {
      setRecipientId(MOCK_RECIPIENTS[0].id);
    }
  }, [preSelectedRecipient, isOpen]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!reference) {
      setError('Reference number is required.');
      return;
    }

    setLoading(true);
    try {
      const request: LabelGenerationRequest = {
        senderId,
        recipientId,
        reference,
        serviceType,
        weight,
        dimensions: { l: 10, w: 10, h: 10 }, // Simplified for UI
        options: {
          createReturnLabel,
          emailLabelToRecipient: emailLabel,
          notifyEmails
        }
      };

      const shipment = await n8nService.createLabel(request);
      onSuccess(shipment);
      onClose();
    } catch (err) {
      setError('Failed to generate label via N8N. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const toggleNotifyEmail = (email: string) => {
    setNotifyEmails(prev => 
      prev.includes(email) 
        ? prev.filter(e => e !== email)
        : [...prev, email]
    );
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-3xl overflow-hidden flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="bg-slate-900 text-white p-6 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg">
              <Truck size={24} className="text-white" />
            </div>
            <div>
              <h2 className="text-xl font-bold">Generate FedEx Label</h2>
              <p className="text-slate-400 text-sm">Create shipment via N8N Workflow</p>
            </div>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Body */}
        <div className="p-6 overflow-y-auto custom-scrollbar flex-1">
          {error && (
            <div className="mb-4 p-4 bg-red-50 text-red-700 rounded-lg flex items-center gap-2">
              <AlertCircle size={20} />
              {error}
            </div>
          )}

          <form id="label-form" onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">

            {/* Left Column: Addresses */}
            <div className="space-y-6">
              <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider border-b pb-2">Route</h3>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Sender (Origin)</label>
                <select 
                  value={senderId} 
                  onChange={(e) => setSenderId(e.target.value)}
                  className="w-full rounded-md border border-slate-300 p-2.5 bg-slate-50 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
                >
                  {MOCK_SENDERS.map(s => (
                    <option key={s.id} value={s.id}>{s.name} - {s.city}, {s.state}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Recipient (Destination)</label>
                <select 
                  value={recipientId} 
                  onChange={(e) => setRecipientId(e.target.value)}
                  className="w-full rounded-md border border-slate-300 p-2.5 bg-slate-50 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
                >
                  {MOCK_RECIPIENTS.map(r => (
                    <option key={r.id} value={r.id}>{r.name} - {r.company ? r.company + ' - ' : ''} {r.city}, {r.state}</option>
                  ))}
                </select>
                <p className="text-xs text-slate-500 mt-1">Select from address book.</p>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">
                  Reference <span className="text-red-500">*</span>
                </label>
                <input 
                  type="text" 
                  value={reference}
                  onChange={(e) => setReference(e.target.value)}
                  placeholder="PO Number, Invoice #, etc."
                  className="w-full rounded-md border border-slate-300 p-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
                />
                <p className="text-xs text-indigo-600 mt-1">Required for billing and tracking.</p>
              </div>
            </div>

            {/* Right Column: Service & Options */}
            <div className="space-y-6">
              <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider border-b pb-2">Service & Options</h3>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Service Type</label>
                <select 
                  value={serviceType}
                  onChange={(e) => setServiceType(e.target.value)}
                  className="w-full rounded-md border border-slate-300 p-2.5 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
                >
                  {SERVICE_TYPES.map(s => (
                    <option key={s.value} value={s.value}>{s.label}</option>
                  ))}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Weight (lbs)</label>
                  <input 
                    type="number" 
                    min="1"
                    value={weight}
                    onChange={(e) => setWeight(Number(e.target.value))}
                    className="w-full rounded-md border border-slate-300 p-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
                  />
                </div>
                <div>
                  {/* Visual placeholder for Dims */}
                   <label className="block text-sm font-medium text-slate-700 mb-1">Dims (LxWxH)</label>
                   <input disabled value="10 x 10 x 10" className="w-full rounded-md border border-slate-200 bg-slate-100 p-2.5 text-slate-500 cursor-not-allowed" />
                </div>
              </div>

              <div className="space-y-3 pt-2">
                <label className="flex items-center gap-3 p-3 border rounded-lg hover:bg-slate-50 cursor-pointer transition-colors">
                  <input 
                    type="checkbox" 
                    checked={createReturnLabel}
                    onChange={(e) => setCreateReturnLabel(e.target.checked)}
                    className="w-5 h-5 text-indigo-600 rounded focus:ring-indigo-500" 
                  />
                  <div>
                    <span className="font-medium text-slate-800">Include Return Label</span>
                    <p className="text-xs text-slate-500">Generate a return label in the payload</p>
                  </div>
                </label>

                <label className="flex items-center gap-3 p-3 border rounded-lg hover:bg-slate-50 cursor-pointer transition-colors">
                  <input 
                    type="checkbox" 
                    checked={emailLabel}
                    onChange={(e) => setEmailLabel(e.target.checked)}
                    className="w-5 h-5 text-indigo-600 rounded focus:ring-indigo-500" 
                  />
                  <div>
                    <span className="font-medium text-slate-800">Email Label to Recipient</span>
                    <p className="text-xs text-slate-500">N8N will email PDF to recipient address</p>
                  </div>
                </label>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Internal Notifications</label>
                <div className="flex flex-wrap gap-2">
                  {INTERNAL_USERS.map(user => (
                    <button
                      key={user.value}
                      type="button"
                      onClick={() => toggleNotifyEmail(user.value)}
                      className={`text-xs px-3 py-1.5 rounded-full border transition-all ${
                        notifyEmails.includes(user.value)
                          ? 'bg-indigo-100 border-indigo-200 text-indigo-800 font-medium'
                          : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-300'
                      }`}
                    >
                      {user.label}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </form>
        </div>

        {/* Footer */}
        <div className="bg-slate-50 p-6 border-t border-slate-200 flex justify-end gap-3">
          <button 
            type="button" 
            onClick={onClose}
            className="px-5 py-2.5 rounded-lg text-slate-700 hover:bg-slate-200 font-medium transition-colors"
          >
            Cancel
          </button>
          <button 
            form="label-form"
            type="submit"
            disabled={loading}
            className="px-6 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-medium shadow-lg shadow-indigo-200 flex items-center gap-2 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {loading ? <Loader2 className="animate-spin" size={20} /> : <Save size={20} />}
            Generate Label
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MOCK_RECIPIENTS, MOCK_SENDERS } from '../constants';
import { Address } from '../types';
import { Plus, Search, MapPin, Package, Trash2, Wand2, Loader2, CheckCircle2 } from 'lucide-react';
import { parseAddressWithGemini } from '../services/geminiService';

interface AddressBookProps {
  onGenerateLabel: (recipient: Address) => void;
}

export const AddressBook: React.FC<AddressBookProps> = ({ onGenerateLabel }) => {
  const [activeTab, setActiveTab] = useState<'RECIPIENT' | 'SENDER'>('RECIPIENT');
  const [recipients, setRecipients] = useState(MOCK_RECIPIENTS);
  const [senders, setSenders] = useState(MOCK_SENDERS);
  const [searchTerm, setSearchTerm] = useState('');

  // AI Parsing State
  const [showAiParser, setShowAiParser] = useState(false);
  const [rawAddress, setRawAddress] = useState('');
  const [isParsing, setIsParsing] = useState(false);

  const data = activeTab === 'RECIPIENT' ? recipients : senders;

  const filteredData = data.filter(d => 
    d.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    d.company?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    d.city.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleAiParse = async () => {
    if (!rawAddress.trim()) return;
    setIsParsing(true);
    try {
      const parsed = await parseAddressWithGemini(rawAddress);

      const newAddress: Address = {
        id: `addr_${Date.now()}`,
        name: parsed.name || 'Unknown',
        company: parsed.company,
        street1: parsed.street1,
        street2: parsed.street2,
        city: parsed.city,
        state: parsed.state,
        zip: parsed.zip,
        country: parsed.country || 'US',
        phone: parsed.phone || '',
        email: parsed.email || '',
        type: activeTab
      };

      if (activeTab === 'RECIPIENT') {
        setRecipients([newAddress, ...recipients]);
      } else {
        setSenders([newAddress, ...senders]);
      }

      setRawAddress('');
      setShowAiParser(false);
    } catch (e) {
      alert("Failed to parse address. Please try again or enter manually.");
    } finally {
      setIsParsing(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Address Book</h2>
          <p className="text-slate-500">Manage your shipping contacts</p>
        </div>

        <div className="flex gap-2">
           <button 
            onClick={() => setShowAiParser(!showAiParser)}
            className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-purple-600 to-indigo-600 text-white rounded-lg hover:shadow-lg transition-all"
          >
            <Wand2 size={18} />
            <span className="hidden sm:inline">AI Smart Add</span>
          </button>
          <button className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors">
            <Plus size={18} />
            <span className="hidden sm:inline">Manual Add</span>
          </button>
        </div>
      </div>

      {/* AI Parser Panel */}
      {showAiParser && (
        <div className="bg-indigo-50 border border-indigo-100 rounded-xl p-6 animate-fade-in">
          <h3 className="text-lg font-semibold text-indigo-900 mb-2 flex items-center gap-2">
            <Wand2 size={20} /> Paste Raw Address
          </h3>
          <p className="text-indigo-700 text-sm mb-4">
            Paste a full address block (e.g. from an email signature) and Gemini AI will format it for you.
          </p>
          <textarea
            value={rawAddress}
            onChange={(e) => setRawAddress(e.target.value)}
            placeholder="e.g. John Doe, Acme Corp, 123 Main St, Suite 400, Austin TX 78701 (555) 123-4567"
            className="w-full p-3 rounded-lg border-indigo-200 focus:ring-2 focus:ring-indigo-500 outline-none text-slate-800"
            rows={3}
          />
          <div className="flex justify-end mt-3">
            <button 
              onClick={handleAiParse}
              disabled={isParsing || !rawAddress}
              className="px-4 py-2 bg-indigo-600 text-white rounded-lg flex items-center gap-2 disabled:opacity-50"
            >
              {isParsing ? <Loader2 className="animate-spin" size={18} /> : <CheckCircle2 size={18} />}
              Parse & Save
            </button>
          </div>
        </div>
      )}

      {/* Tabs */}
      <div className="border-b border-slate-200">
        <nav className="-mb-px flex space-x-8">
          <button
            onClick={() => setActiveTab('RECIPIENT')}
            className={`whitespace-nowrap pb-4 px-1 border-b-2 font-medium text-sm transition-colors ${
              activeTab === 'RECIPIENT'
                ? 'border-indigo-500 text-indigo-600'
                : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
            }`}
          >
            Recipients
          </button>
          <button
            onClick={() => setActiveTab('SENDER')}
            className={`whitespace-nowrap pb-4 px-1 border-b-2 font-medium text-sm transition-colors ${
              activeTab === 'SENDER'
                ? 'border-indigo-500 text-indigo-600'
                : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
            }`}
          >
            Senders (Origins)
