interface AddressBookProps {
  onGenerateLabel: (recipient: Address) => void;
}

export const AddressBook: React.FC<AddressBookProps> = ({ onGenerateLabel }) => {
  const [activeTab, setActiveTab] = useState<'RECIPIENT' | 'SENDER'>('RECIPIENT');
  const [recipients, setRecipients] = useState(MOCK_RECIPIENTS);
  const [senders, setSenders] = useState(MOCK_SENDERS);
  const [searchTerm, setSearchTerm] = useState('');

  // Manual Add State
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newAddress, setNewAddress] = useState<Partial<Address>>({
    country: 'US'
  });

  const data = activeTab === 'RECIPIENT' ? recipients : senders;

  const filteredData = data.filter(d => 
    d.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    d.company?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    d.city.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleSaveAddress = (e: React.FormEvent) => {
    e.preventDefault();

    // Basic validation
    if (!newAddress.name || !newAddress.street1 || !newAddress.city || !newAddress.state || !newAddress.zip) {
      alert("Please fill in required fields (Name, Street, City, State, Zip)");
      return;
    }

    const address: Address = {
      id: `addr_${Date.now()}`,
      name: newAddress.name || '',
      company: newAddress.company || '',
      street1: newAddress.street1 || '',
      street2: newAddress.street2 || '',
      city: newAddress.city || '',
      state: newAddress.state || '',
      zip: newAddress.zip || '',
      country: newAddress.country || 'US',
      phone: newAddress.phone || '',
      email: newAddress.email || '',
      type: activeTab
    };

    if (activeTab === 'RECIPIENT') {
      setRecipients([address, ...recipients]);
    } else {
      setSenders([address, ...senders]);
    }

    // Reset and close
    setNewAddress({ country: 'US' });
    setIsAddModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this contact?')) {
      if (activeTab === 'RECIPIENT') {
        setRecipients(recipients.filter(r => r.id !== id));
      } else {
        setSenders(senders.filter(s => s.id !== id));
      }
