interface AddressBookProps {
  onGenerateLabel: (recipient: Address) => void;
}

// Moved outside to prevent re-mounting and focus loss
const InputField = ({ label, value, onChange, placeholder, required = false, type = "text" }: any) => (
  <div>
    <label className="block text-sm font-medium text-slate-700 mb-1">
      {label} {required && <span className="text-red-500">*</span>}
    </label>
    <input 
      type={type}
      required={required}
      value={value || ''}
      onChange={onChange}
      placeholder={placeholder}
      className="w-full rounded-md border border-slate-300 p-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none text-sm"
    />
  </div>
);

