import React, { useState, useEffect, useRef } from 'react';
import { Address } from '../types';
import { Plus, Search, MapPin, Package, Trash2, X, Save, Building, User, Phone, Mail, ArrowRightLeft, Loader2 } from 'lucide-react';

const GEOAPIFY_API_KEY = "075b96e25ae54d67a54e63d7f861b080";

interface AddressBookProps {
  onGenerateLabel: (recipient: Address) => void;
  recipients: Address[];
  senders: Address[];
  onUpdateRecipients: (addresses: Address[]) => void;
  onUpdateSenders: (addresses: Address[]) => void;
