  const data = activeTab === 'RECIPIENT' ? recipients : senders;

  const filteredData = data.filter(d => 
    d.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    d.company?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    d.city.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleSaveAddress = (e: React.FormEvent) => {
    e.preventDefault();

    // Basic validation
    if (!newAddress.name || !newAddress.street1 || !newAddress.city || !newAddress.state || !newAddress.zip || !newAddress.phone || !newAddress.email) {
      alert("Please fill in all required fields:\n- Name\n- Street Address\n- City\n- State\n- Zip Code\n- Phone Number\n- Email Address");
      return;
