import React, { useState, useEffect } from 'react';
import { X, Truck, Save, Loader2, AlertCircle, Plus, ChevronDown } from 'lucide-react';
import { Address, LabelGenerationRequest, Shipment } from '../types';
import { SERVICE_TYPES, PACKAGE_TYPES, INTERNAL_USERS } from '../constants';
import { n8nService } from '../services/n8nService';
import { AddressForm } from './AddressForm';

interface CreateLabelModalProps {
  isOpen: boolean;
  onClose: () => void;
  preSelectedRecipient?: Address | null;
  onSuccess: (shipment: Shipment) => void;
  recipients: Address[];
  senders: Address[];
  onAddRecipient: (addr: Address) => void;
  onAddSender: (addr: Address) => void;
}

export const CreateLabelModal: React.FC<CreateLabelModalProps> = ({
  isOpen,
  onClose,
  preSelectedRecipient,
  onSuccess,
  recipients,
  senders,
  onAddRecipient,
  onAddSender
}) => {
  const [loading, setLoading] = useState(false);
  const [senderId, setSenderId] = useState('');
  const [recipientId, setRecipientId] = useState('');
  const [reference, setReference] = useState('');
  const [serviceType, setServiceType] = useState(SERVICE_TYPES[0].value);
  const [packageType, setPackageType] = useState(PACKAGE_TYPES[0].value);
  const [weight, setWeight] = useState(1);

  // Options
  const [createReturnLabel, setCreateReturnLabel] = useState(false);
  const [emailLabel, setEmailLabel] = useState(false);
  const [notifyEmails, setNotifyEmails] = useState<string[]>([]);

  const [error, setError] = useState('');

  // Local/Temporary Address State
  // These lists include props.recipients/senders PLUS any one-offs created in this session that weren't saved to DB
  const [localRecipients, setLocalRecipients] = useState<Address[]>([]);
  const [localSenders, setLocalSenders] = useState<Address[]>([]);

  // Add Address Modal State
  const [isAddAddressOpen, setIsAddAddressOpen] = useState(false);
  const [addAddressType, setAddAddressType] = useState<'SENDER' | 'RECIPIENT'>('RECIPIENT');

  // Sync props with local state
  useEffect(() => {
    setLocalRecipients(prev => {
        // Merge prop recipients with existing local one-offs (if any)
        // Simple strategy: just reset to props for now, unless we want to keep one-offs across re-renders
        // For simplicity, let's just use props + one-offs we add manually
        const existingIds = new Set(recipients.map(r => r.id));
        const oneOffs = prev.filter(r => !existingIds.has(r.id));
        return [...recipients, ...oneOffs];
    });
  }, [recipients]);

  useEffect(() => {
    setLocalSenders(prev => {
        const existingIds = new Set(senders.map(s => s.id));
        const oneOffs = prev.filter(s => !existingIds.has(s.id));
        return [...senders, ...oneOffs];
    });
  }, [senders]);

  // Initialize defaults
  useEffect(() => {
    if (isOpen) {
       if (localSenders.length > 0 && !senderId) {
         setSenderId(localSenders[0].id);
       }

       if (preSelectedRecipient) {
          setRecipientId(preSelectedRecipient.id);
       } else if (localRecipients.length > 0 && !recipientId) {
          setRecipientId(localRecipients[0].id);
       }
    }
  }, [isOpen, preSelectedRecipient, localSenders, localRecipients]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!reference) {
      setError('Reference number is required.');
      return;
    }

    if (!senderId || !recipientId) {
      setError('Both Sender and Recipient addresses are required.');
      return;
    }

    setLoading(true);
    try {
      const request: LabelGenerationRequest = {
        senderId,
        recipientId,
        reference,
        serviceType,
        packageType,
        weight,
        dimensions: { l: 10, w: 10, h: 10 }, // Simplified for UI
        options: {
          createReturnLabel,
          emailLabelToRecipient: emailLabel,
          notifyEmails
        }
      };

      const shipment = await n8nService.createLabel(request);
      onSuccess(shipment);
      onClose();
    } catch (err) {
      setError('Failed to generate label via N8N. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleAddNew = (type: 'SENDER' | 'RECIPIENT') => {
    setAddAddressType(type);
    setIsAddAddressOpen(true);
  };

  const handleSaveNewAddress = (address: Address, saveToBook: boolean) => {
    if (saveToBook) {
      // Save permanently via App.tsx handlers
      if (address.type === 'RECIPIENT') {
        onAddRecipient(address);
      } else {
        onAddSender(address);
      }
    } else {
      // Add locally only (One-off)
      if (address.type === 'RECIPIENT') {
        setLocalRecipients(prev => [address, ...prev]);
      } else {
        setLocalSenders(prev => [address, ...prev]);
      }
    }

    // Automatically select the new address
    if (address.type === 'RECIPIENT') {
        setRecipientId(address.id);
    } else {
        setSenderId(address.id);
    }

    setIsAddAddressOpen(false);
  };

  const toggleNotifyEmail = (email: string) => {
    setNotifyEmails(prev => 
      prev.includes(email) 
        ? prev.filter(e => e !== email)
        : [...prev, email]
    );
  };

  if (!isOpen) return null;

  return (
    <>
      <div className="fixed inset-0 z-40 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm p-4">
        <div className="bg-white rounded-xl shadow-2xl w-full max-w-3xl overflow-hidden flex flex-col max-h-[90vh]">

          {/* Header */}
          <div className="bg-slate-900 text-white p-6 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-indigo-600 rounded-lg">
                <Truck size={24} className="text-white" />
              </div>
              <div>
                <h2 className="text-xl font-bold">Generate FedEx Label</h2>
                <p className="text-slate-400 text-sm">Create shipment via N8N Workflow</p>
              </div>
            </div>
            <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
              <X size={24} />
            </button>
          </div>

          {/* Body */}
          <div className="p-6 overflow-y-auto custom-scrollbar flex-1">
            {error && (
              <div className="mb-4 p-4 bg-red-50 text-red-700 rounded-lg flex items-center gap-2">
                <AlertCircle size={20} />
                {error}
              </div>
            )}

            <form id="label-form" onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">

              {/* Left Column: Addresses */}
              <div className="space-y-6">
                <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider border-b pb-2">Route</h3>

                <div>
                  <div className="flex justify-between items-center mb-1">
                    <label className="block text-sm font-medium text-slate-700">Sender (Origin)</label>
                    <button 
                        type="button" 
                        onClick={() => handleAddNew('SENDER')}
                        className="text-xs text-indigo-600 hover:text-indigo-800 flex items-center gap-1 font-medium"
                    >
                        <Plus size={12} /> New Sender
                    </button>
                  </div>
                  <div className="relative">
                      <select 
                        value={senderId} 
                        onChange={(e) => setSenderId(e.target.value)}
                        className="w-full rounded-md border border-slate-300 p-2.5 bg-slate-50 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none appearance-none"
                      >
                        {localSenders.map(s => (
                          <option key={s.id} value={s.id}>{s.name} - {s.city}, {s.state}</option>
                        ))}
                      </select>
                      <ChevronDown size={16} className="absolute right-3 top-3 text-slate-400 pointer-events-none" />
                  </div>
                </div>

                <div>
                   <div className="flex justify-between items-center mb-1">
                    <label className="block text-sm font-medium text-slate-700">Recipient (Destination)</label>
                    <button 
                        type="button" 
                        onClick={() => handleAddNew('RECIPIENT')}
                        className="text-xs text-indigo-600 hover:text-indigo-800 flex items-center gap-1 font-medium"
                    >
                        <Plus size={12} /> New Recipient
                    </button>
                  </div>
                  <div className="relative">
                      <select 
                        value={recipientId} 
                        onChange={(e) => setRecipientId(e.target.value)}
                        className="w-full rounded-md border border-slate-300 p-2.5 bg-slate-50 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none appearance-none"
                      >
                        {localRecipients.map(r => (
                          <option key={r.id} value={r.id}>{r.name} - {r.company ? r.company + ' - ' : ''} {r.city}, {r.state}</option>
                        ))}
                      </select>
                      <ChevronDown size={16} className="absolute right-3 top-3 text-slate-400 pointer-events-none" />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">
                    Reference <span className="text-red-500">*</span>
                  </label>
                  <input 
                    type="text" 
                    value={reference}
                    onChange={(e) => setReference(e.target.value)}
                    placeholder="PO Number, Invoice #, etc."
                    className="w-full rounded-md border border-slate-300 p-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
                  />
                  <p className="text-xs text-indigo-600 mt-1">Required for billing and tracking.</p>
                </div>
              </div>

              {/* Right Column: Service & Options */}
              <div className="space-y-6">
                <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider border-b pb-2">Service & Options</h3>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Service Type</label>
                  <select 
                    value={serviceType}
                    onChange={(e) => setServiceType(e.target.value)}
