import { LabelGenerationRequest, Shipment, ShipmentStatus } from '../types';
import { MOCK_SENDERS, MOCK_RECIPIENTS } from '../constants';

// This service mocks the interaction with N8N webhooks.
// In a real application, these would be fetch() calls to the URLs in constants.ts

const LOCAL_STORAGE_KEY = 'fedex_app_shipments';

const getStoredShipments = (): Shipment[] => {
  const stored = localStorage.getItem(LOCAL_STORAGE_KEY);
  return stored ? JSON.parse(stored) : [];
};

const saveShipment = (shipment: Shipment) => {
  const current = getStoredShipments();
  localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify([shipment, ...current]));
};

export const n8nService = {
  createLabel: async (request: LabelGenerationRequest): Promise<Shipment> => {
    // Simulate Network Latency
    await new Promise(resolve => setTimeout(resolve, 1500));

    const sender = MOCK_SENDERS.find(s => s.id === request.senderId) || MOCK_SENDERS[0];
    const recipient = MOCK_RECIPIENTS.find(r => r.id === request.recipientId) || MOCK_RECIPIENTS[0];

    // Mock Response from N8N
    const newShipment: Shipment = {
      id: `shp_${Date.now()}`,
      trackingNumber: `1234${Math.floor(Math.random() * 100000000)}`, // Mock Tracking
      reference: request.reference,
      status: ShipmentStatus.CREATED,
      createdDate: new Date().toISOString(),
      sender,
      recipient,
      serviceType: request.serviceType,
      packageType: request.packageType,
      weight: request.weight,
      isReturnLabel: request.options.createReturnLabel,
      notifications: request.options.notifyEmails,
      labelUrl: 'https://dummyimage.com/600x800/fff/000.png&text=FEDEX+LABEL+SAMPLE',
      price: Math.floor(Math.random() * 60) + 15.50 // Mock price between 15.50 and 75.50
    };

    saveShipment(newShipment);
    return newShipment;
  },

  getHistory: async (): Promise<Shipment[]> => {
    // Simulate Network Latency
    await new Promise(resolve => setTimeout(resolve, 500));
    return getStoredShipments();
  },

  // This would typically trigger a webhook to refresh status
  refreshTracking: async (trackingNumber: string): Promise<ShipmentStatus> => {
    await new Promise(resolve => setTimeout(resolve, 1000));
    const statuses = Object.values(ShipmentStatus);
    const randomStatus = statuses[Math.floor(Math.random() * statuses.length)];
    return randomStatus;
  }
};

import React, { useState, useEffect } from 'react';
import { X, Truck, Save, Loader2, AlertCircle, Plus, ChevronDown } from 'lucide-react';
import { Address, LabelGenerationRequest, Shipment } from '../types';
import { SERVICE_TYPES, PACKAGE_TYPES, INTERNAL_USERS } from '../constants';
import { n8nService } from '../services/n8nService';
import { AddressForm } from './AddressForm';

interface CreateLabelModalProps {
  isOpen: boolean;
  onClose: () => void;
  preSelectedRecipient?: Address | null;
  onSuccess: (shipment: Shipment) => void;
  recipients: Address[];
  senders: Address[];
  onAddRecipient: (addr: Address) => void;
  onAddSender: (addr: Address) => void;
}

export const CreateLabelModal: React.FC<CreateLabelModalProps> = ({
  isOpen,
  onClose,
  preSelectedRecipient,
  onSuccess,
  recipients,
  senders,
  onAddRecipient,
  onAddSender
}) => {
  const [loading, setLoading] = useState(false);
  const [senderId, setSenderId] = useState('');
  const [recipientId, setRecipientId] = useState('');
  const [reference, setReference] = useState('');

  // Defaults updated as requested
  const [serviceType, setServiceType] = useState('STANDARD_OVERNIGHT');
  const [packageType, setPackageType] = useState('FEDEX_ENVELOPE');

  const [weight, setWeight] = useState(1);

  // Options
  const [createReturnLabel, setCreateReturnLabel] = useState(false);
  const [emailLabel, setEmailLabel] = useState(false);
  const [notifyEmails, setNotifyEmails] = useState<string[]>([]);

  const [error, setError] = useState('');

  // Local/Temporary Address State
  // These lists include props.recipients/senders PLUS any one-offs created in this session that weren't saved to DB
  const [localRecipients, setLocalRecipients] = useState<Address[]>([]);
  const [localSenders, setLocalSenders] = useState<Address[]>([]);

  // Add Address Modal State
  const [isAddAddressOpen, setIsAddAddressOpen] = useState(false);
  const [addAddressType, setAddAddressType] = useState<'SENDER' | 'RECIPIENT'>('RECIPIENT');

  // Sync props with local state
  useEffect(() => {
    setLocalRecipients(prev => {
        // Merge prop recipients with existing local one-offs (if any)
        const existingIds = new Set(recipients.map(r => r.id));
        const oneOffs = prev.filter(r => !existingIds.has(r.id));
        return [...recipients, ...oneOffs];
    });
  }, [recipients]);

  useEffect(() => {
    setLocalSenders(prev => {
        const existingIds = new Set(senders.map(s => s.id));
        const oneOffs = prev.filter(s => !existingIds.has(s.id));
        return [...senders, ...oneOffs];
    });
  }, [senders]);

  // Initialize defaults
  useEffect(() => {
    if (isOpen) {
       if (localSenders.length > 0 && !senderId) {
         setSenderId(localSenders[0].id);
       }

       if (preSelectedRecipient) {
          setRecipientId(preSelectedRecipient.id);
       } else if (localRecipients.length > 0 && !recipientId) {
          setRecipientId(localRecipients[0].id);
       }
    }
  }, [isOpen, preSelectedRecipient, localSenders, localRecipients]);

  const resetForm = () => {
    setReference('');
    setWeight(1);
    setServiceType('STANDARD_OVERNIGHT');
    setPackageType('FEDEX_ENVELOPE');
    setCreateReturnLabel(false);
    setEmailLabel(false);
    setNotifyEmails([]);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!reference) {
      setError('Reference number is required.');
      return;
    }

    if (!senderId || !recipientId) {
      setError('Both Sender and Recipient addresses are required.');
      return;
    }

    setLoading(true);
    try {
      const request: LabelGenerationRequest = {
        senderId,
        recipientId,
        reference,
        serviceType,
        packageType,
        weight,
        dimensions: { l: 10, w: 10, h: 10 }, // Simplified for UI
        options: {
          createReturnLabel,
          emailLabelToRecipient: emailLabel,
          notifyEmails
        }
      };

      const shipment = await n8nService.createLabel(request);
      resetForm(); // Clear form on success
      onSuccess(shipment);
      onClose();
    } catch (err) {
      setError('Failed to generate label via N8N. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleAddNew = (type: 'SENDER' | 'RECIPIENT') => {
    setAddAddressType(type);
    setIsAddAddressOpen(true);
  };

  const handleSaveNewAddress = (address: Address, saveToBook: boolean) => {
    if (saveToBook) {
      // Save permanently via App.tsx handlers
      if (address.type === 'RECIPIENT') {
        onAddRecipient(address);
      } else {
        onAddSender(address);
      }
    } else {
      // Add locally only (One-off)
      if (address.type === 'RECIPIENT') {
        setLocalRecipients(prev => [address, ...prev]);
      } else {
        setLocalSenders(prev => [address, ...prev]);
      }
    }

    // Automatically select the new address
    if (address.type === 'RECIPIENT') {
        setRecipientId(address.id);
    } else {
        setSenderId(address.id);
    }

    setIsAddAddressOpen(false);
  };

  const toggleNotifyEmail = (email: string) => {
    setNotifyEmails(prev => 
      prev.includes(email) 
        ? prev.filter(e => e !== email)
        : [...prev, email]
    );
  };

  if (!isOpen) return null;

  return (
    <>
      <div className="fixed inset-0 z-40 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm p-4">
        <div className="bg-white rounded-xl shadow-2xl w-full max-w-3xl overflow-hidden flex flex-col max-h-[90vh]">

          {/* Header */}
          <div className="bg-slate-900 text-white p-6 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-indigo-600 rounded-lg">
                <Truck size={24} className="text-white" />
              </div>
              <div>
                <h2 className="text-xl font-bold">Generate FedEx Label</h2>
                <p className="text-slate-400 text-sm">Create shipment via N8N Workflow</p>
              </div>
            </div>
            <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
              <X size={24} />
            </button>
          </div>

          {/* Body */}
          <div className="p-6 overflow-y-auto custom-scrollbar flex-1">
            {error && (
              <div className="mb-4 p-4 bg-red-50 text-red-700 rounded-lg flex items-center gap-2">
                <AlertCircle size={20} />
                {error}
              </div>
            )}

            <form id="label-form" onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">

              {/* Left Column: Addresses */}
              <div className="space-y-6">
                <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider border-b pb-2">Route</h3>

                <div>
                  <div className="flex justify-between items-center mb-1">
                    <label className="block text-sm font-medium text-slate-700">Sender (Origin)</label>
                    <button 
                        type="button" 
                        onClick={() => handleAddNew('SENDER')}
                        className="text-xs text-indigo-600 hover:text-indigo-800 flex items-center gap-1 font-medium bg-indigo-50 px-2 py-1 rounded hover:bg-indigo-100 transition-colors"
                    >
                        <Plus size={12} /> New Sender
                    </button>
                  </div>
                  <div className="relative group">
                      <select 
                        value={senderId} 
                        onChange={(e) => setSenderId(e.target.value)}
                        className="w-full rounded-md border border-slate-300 p-2.5 bg-white text-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none appearance-none cursor-pointer hover:border-indigo-400 transition-colors shadow-sm"
                      >
                        {localSenders.map(s => (
                          <option key={s.id} value={s.id}>{s.name} - {s.city}, {s.state}</option>
                        ))}
                      </select>
                      <ChevronDown size={16} className="absolute right-3 top-3 text-slate-500 pointer-events-none group-hover:text-indigo-600 transition-colors" />
                  </div>
                </div>

                <div>
                   <div className="flex justify-between items-center mb-1">
                    <label className="block text-sm font-medium text-slate-700">Recipient (Destination)</label>
                    <button 
                        type="button" 
                        onClick={() => handleAddNew('RECIPIENT')}
                        className="text-xs text-indigo-600 hover:text-indigo-800 flex items-center gap-1 font-medium bg-indigo-50 px-2 py-1 rounded hover:bg-indigo-100 transition-colors"
                    >
                        <Plus size={12} /> New Recipient
                    </button>
                  </div>
                  <div className="relative group">
                      <select 
                        value={recipientId} 
                        onChange={(e) => setRecipientId(e.target.value)}
                        className="w-full rounded-md border border-slate-300 p-2.5 bg-white text-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none appearance-none cursor-pointer hover:border-indigo-400 transition-colors shadow-sm"
                      >
                        {localRecipients.map(r => (
                          <option key={r.id} value={r.id}>{r.name} - {r.company ? r.company + ' - ' : ''} {r.city}, {r.state}</option>
                        ))}
                      </select>
                      <ChevronDown size={16} className="absolute right-3 top-3 text-slate-500 pointer-events-none group-hover:text-indigo-600 transition-colors" />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">
                    Reference <span className="text-red-500">*</span>
                  </label>
                  <input 
                    type="text" 
                    value={reference}
                    onChange={(e) => setReference(e.target.value)}
                    placeholder="PO Number, Invoice #, etc."
                    className="w-full rounded-md border border-slate-300 p-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none shadow-sm"
                  />
                  <p className="text-xs text-indigo-600 mt-1">Required for billing and tracking.</p>
                </div>
              </div>

              {/* Right Column: Service & Options */}
              <div className="space-y-6">
                <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider border-b pb-2">Service & Options</h3>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Service Type</label>
                  <div className="relative group">
                    <select 
                      value={serviceType}
                      onChange={(e) => setServiceType(e.target.value)}
                      className="w-full rounded-md border border-slate-300 p-2.5 bg-white text-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none appearance-none cursor-pointer hover:border-indigo-400 transition-colors shadow-sm"
                    >
                      {SERVICE_TYPES.map(s => (
                        <option key={s.value} value={s.value}>{s.label}</option>
                      ))}
                    </select>
                    <ChevronDown size={16} className="absolute right-3 top-3 text-slate-500 pointer-events-none group-hover:text-indigo-600 transition-colors" />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Package Type</label>
                  <div className="relative group">
                    <select 
                      value={packageType}
                      onChange={(e) => setPackageType(e.target.value)}
                      className="w-full rounded-md border border-slate-300 p-2.5 bg-white text-slate-700 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none appearance-none cursor-pointer hover:border-indigo-400 transition-colors shadow-sm"
                    >
                      {PACKAGE_TYPES.map(p => (
                        <option key={p.value} value={p.value}>{p.label}</option>
                      ))}
                    </select>
                    <ChevronDown size={16} className="absolute right-3 top-3 text-slate-500 pointer-events-none group-hover:text-indigo-600 transition-colors" />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Weight (lbs)</label>
                    <input 
                      type="number" 
                      min="1"
                      value={weight}
                      onChange={(e) => setWeight(Number(e.target.value))}
                      className="w-full rounded-md border border-slate-300 p-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none shadow-sm"
                    />
                  </div>
                  <div>
                    {/* Visual placeholder for Dims - dependent on package type usually, but we keep simple */}
                     <label className="block text-sm font-medium text-slate-700 mb-1">Dims (LxWxH)</label>
                     <input disabled value={packageType === 'FEDEX_ENVELOPE' ? 'N/A' : '10 x 10 x 10'} className="w-full rounded-md border border-slate-200 bg-slate-100 p-2.5 text-slate-500 cursor-not-allowed shadow-inner" />
                  </div>
                </div>

                <div className="space-y-3 pt-2">
                  <label className="flex items-center gap-3 p-3 border rounded-lg hover:bg-slate-50 cursor-pointer transition-colors bg-white shadow-sm">
                    <input 
                      type="checkbox" 
                      checked={createReturnLabel}
                      onChange={(e) => setCreateReturnLabel(e.target.checked)}
                      className="w-5 h-5 text-indigo-600 rounded focus:ring-indigo-500" 
                    />
                    <div>
                      <span className="font-medium text-slate-800">Include Return Label</span>
                      <p className="text-xs text-slate-500">Generate a return label in the payload</p>
                    </div>
                  </label>

                  <label className="flex items-center gap-3 p-3 border rounded-lg hover:bg-slate-50 cursor-pointer transition-colors bg-white shadow-sm">
                    <input 
                      type="checkbox" 
                      checked={emailLabel}
                      onChange={(e) => setEmailLabel(e.target.checked)}
                      className="w-5 h-5 text-indigo-600 rounded focus:ring-indigo-500" 
                    />
                    <div>
                      <span className="font-medium text-slate-800">Email Label to Recipient</span>
                      <p className="text-xs text-slate-500">N8N will email PDF to recipient address</p>
                    </div>
                  </label>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-2">Internal Notifications</label>
                  <div className="flex flex-wrap gap-2">
                    {INTERNAL_USERS.map(user => (
                      <button
                        key={user.value}
                        type="button"
                        onClick={() => toggleNotifyEmail(user.value)}
                        className={`text-xs px-3 py-1.5 rounded-full border transition-all ${
                          notifyEmails.includes(user.value)
                            ? 'bg-indigo-100 border-indigo-200 text-indigo-800 font-medium shadow-sm'
                            : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-300 hover:text-indigo-600'
                        }`}
                      >
                        {user.label}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            </form>
          </div>

          {/* Footer */}
          <div className="bg-slate-50 p-6 border-t border-slate-200 flex justify-end gap-3">
            <button 
              type="button" 
              onClick={onClose}
              className="px-5 py-2.5 rounded-lg text-slate-700 hover:bg-slate-200 font-medium transition-colors"
            >
              Cancel
            </button>
            <button 
              form="label-form"
              type="submit"
              disabled={loading}
              className="px-6 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-medium shadow-lg shadow-indigo-200 flex items-center gap-2 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? <Loader2 className="animate-spin" size={20} /> : <Save size={20} />}
              Generate Label
            </button>
          </div>
        </div>
      </div>

      {/* Second Modal for Adding Address */}
      {isAddAddressOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-60 backdrop-blur-sm p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[95vh] border border-slate-200">
                <AddressForm 
                    type={addAddressType}
                    onSave={handleSaveNewAddress}
                    onCancel={() => setIsAddAddressOpen(false)}
                    enableSaveOption={true}
                />
            </div>
        </div>
      )}
    </>
  );
};

import React, { useState } from 'react';
import { Address } from '../types';
import { Plus, Search, MapPin, Package, Trash2, ArrowRightLeft, Pencil } from 'lucide-react';
import { AddressForm } from './AddressForm';

interface AddressBookProps {
  onGenerateLabel: (recipient: Address) => void;
  recipients: Address[];
  senders: Address[];
  onUpdateRecipients: (addresses: Address[]) => void;
  onUpdateSenders: (addresses: Address[]) => void;
}

export const AddressBook: React.FC<AddressBookProps> = ({ 
  onGenerateLabel,
  recipients,
  senders,
  onUpdateRecipients,
  onUpdateSenders
}) => {
  const [activeTab, setActiveTab] = useState<'RECIPIENT' | 'SENDER'>('RECIPIENT');
  const [searchTerm, setSearchTerm] = useState('');
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newContactType, setNewContactType] = useState<'RECIPIENT' | 'SENDER'>('RECIPIENT');
  const [editingContact, setEditingContact] = useState<Address | null>(null);

  const data = activeTab === 'RECIPIENT' ? recipients : senders;

  const filteredData = data.filter(d => 
    d.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    d.company?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    d.city.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleSaveAddress = (address: Address) => {
    let updatedList;
    const currentList = address.type === 'RECIPIENT' ? recipients : senders;

    if (editingContact) {
      // Update existing
      updatedList = currentList.map(a => a.id === address.id ? address : a);
    } else {
      // Create new
      updatedList = [address, ...currentList];
    }

    if (address.type === 'RECIPIENT') {
      onUpdateRecipients(updatedList);
      setActiveTab('RECIPIENT');
    } else {
      onUpdateSenders(updatedList);
      setActiveTab('SENDER');
    }

    setEditingContact(null);
    setIsAddModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this contact?')) {
      if (activeTab === 'RECIPIENT') {
        onUpdateRecipients(recipients.filter(r => r.id !== id));
      } else {
        onUpdateSenders(senders.filter(s => s.id !== id));
      }
    }
  };

  const handleAddClick = () => {
    setEditingContact(null);
    setNewContactType(activeTab);
    setIsAddModalOpen(true);
  };

  const handleEditClick = (contact: Address) => {
    setEditingContact(contact);
    setNewContactType(contact.type);
    setIsAddModalOpen(true);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Address Book</h2>
          <p className="text-slate-500">Manage your shipping contacts</p>
        </div>

        <div className="flex gap-2">
          <button 
            onClick={handleAddClick}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 shadow-sm transition-colors"
          >
            <Plus size={18} />
            <span>Add New Contact</span>
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div className="border-b border-slate-200">
        <nav className="-mb-px flex space-x-8">
          <button
            onClick={() => setActiveTab('RECIPIENT')}
            className={`whitespace-nowrap pb-4 px-1 border-b-2 font-medium text-sm transition-colors ${
              activeTab === 'RECIPIENT'
                ? 'border-indigo-500 text-indigo-600'
                : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
            }`}
          >
            Recipients
          </button>
          <button
            onClick={() => setActiveTab('SENDER')}
            className={`whitespace-nowrap pb-4 px-1 border-b-2 font-medium text-sm transition-colors ${
              activeTab === 'SENDER'
                ? 'border-indigo-500 text-indigo-600'
                : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
            }`}
          >
            Senders (Origins)
          </button>
        </nav>
      </div>

      {/* Search & Table */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50/50">
          <div className="relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Search by name, company, or city..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-200">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Name / Company</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Address</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Contact</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-slate-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-200">
              {filteredData.length === 0 ? (
                 <tr>
                    <td colSpan={4} className="px-6 py-12 text-center text-slate-500">
                      No addresses found. Add one manually.
                    </td>
                 </tr>
              ) : (
                filteredData.map((addr) => (
                  <tr key={addr.id} className="hover:bg-slate-50 group transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <div className="h-10 w-10 flex-shrink-0 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center font-bold">
                          {addr.name.charAt(0)}
                        </div>
                        <div className="ml-4">
                          <div className="text-sm font-medium text-slate-900">{addr.name}</div>
                          <div className="text-sm text-slate-500">{addr.company}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-start gap-2 text-sm text-slate-600">
                        <MapPin size={16} className="mt-0.5 text-slate-400 flex-shrink-0" />
                        <div>
                          <p>{addr.street1} {addr.street2}</p>
                          <p>{addr.city}, {addr.state} {addr.zip}</p>
                          <p className="text-xs text-slate-400">{addr.country}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm text-slate-600">
                        <p>{addr.email}</p>
                        <p className="text-xs text-slate-400">{addr.phone}</p>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      {activeTab === 'RECIPIENT' && (
                        <button 
                          onClick={() => onGenerateLabel(addr)}
                          className="text-indigo-600 hover:text-indigo-900 bg-indigo-50 hover:bg-indigo-100 px-3 py-1.5 rounded-lg inline-flex items-center gap-1 transition-colors mr-2"
                        >
                          <Package size={16} />
                          <span className="hidden lg:inline">Label</span>
                        </button>
                      )}
                      <button 
                        onClick={() => handleEditClick(addr)}
                        className="text-slate-600 hover:text-indigo-600 p-1.5 hover:bg-slate-100 rounded transition-colors mr-1"
                        title="Edit Contact"
                      >
                        <Pencil size={16} />
                      </button>
                      <button 
                        onClick={() => handleDelete(addr.id)}
                        className="text-slate-400 hover:text-red-600 p-1.5 hover:bg-red-50 rounded transition-colors"
                        title="Delete Contact"
                      >
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Manual Add/Edit Modal */}
      {isAddModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <AddressForm 
              initialData={editingContact || {}}
              type={newContactType} 
              onSave={(addr) => handleSaveAddress(addr)}
              onCancel={() => setIsAddModalOpen(false)}
            />
          </div>
        </div>
      )}
    </div>
  );
};

