import React, { useState, useEffect, useRef } from 'react';
import { Address } from '../types';
import { Loader2, Save, Mail, Phone, Building, User, MapPin, X, AlertCircle } from 'lucide-react';
import { settingsService } from '../services/settingsService';

interface AddressFormProps {
  initialData?: Partial<Address>;
  type: 'SENDER' | 'RECIPIENT';
  onSave: (address: Address, saveToBook: boolean) => void;
  onCancel: () => void;
  enableSaveOption?: boolean; // If true, shows checkbox "Save to Address Book"
}

// Reusable Input Component
const InputField = ({ label, value, onChange, placeholder, required = false, type = "text" }: any) => (
  <div>
    <label className="block text-sm font-medium text-slate-700 mb-1">
      {label} {required && <span className="text-red-500">*</span>}
    </label>
    <input 
      type={type}
      required={required}
      value={value || ''}
      onChange={onChange}
      placeholder={placeholder}
      className="w-full rounded-md border border-slate-300 p-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none text-sm"
    />
  </div>
);

// Reusable Autocomplete Component
const AddressAutocomplete = ({ label, value, onChange, onSelect, placeholder, required = false }: any) => {
  const [suggestions, setSuggestions] = useState<any[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [loading, setLoading] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  // Get API key from settings
  const apiKey = settingsService.getSettings().geoapifyApiKey;

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [wrapperRef]);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (value && value.length > 3 && showSuggestions && apiKey) {
        setLoading(true);
        try {
          const response = await fetch(
            `https://api.geoapify.com/v1/geocode/autocomplete?text=${encodeURIComponent(value)}&apiKey=${apiKey}`
          );
          const data = await response.json();
          if (data.features) {
            setSuggestions(data.features);
          }
        } catch (error) {
          console.error("Geoapify Error:", error);
        } finally {
          setLoading(false);
        }
      } else if (!value) {
        setSuggestions([]);
      }
    }, 500);

    return () => clearTimeout(timer);
  }, [value, showSuggestions, apiKey]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onChange(e);
    setShowSuggestions(true);
  };

  const handleSelectSuggestion = (feature: any) => {
    const props = feature.properties;
    const addressData = {
      street1: props.address_line1 || `${props.housenumber || ''} ${props.street || ''}`.trim(),
      city: props.city || props.county || '',
      state: props.state_code || props.state || '',
      zip: props.postcode || '',
      country: props.country_code ? props.country_code.toUpperCase() : 'US'
    };
    onSelect(addressData);
    setShowSuggestions(false);
  };

  return (
    <div className="relative" ref={wrapperRef}>
      <label className="block text-sm font-medium text-slate-700 mb-1">
        {label} {required && <span className="text-red-500">*</span>}
      </label>
      <div className="relative">
        <input 
          type="text"
          required={required}
          value={value || ''}
          onChange={handleInputChange}
          placeholder={placeholder}
          className="w-full rounded-md border border-slate-300 p-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none text-sm"
          autoComplete="off"
        />
        {loading && (
          <div className="absolute right-3 top-2.5">
            <Loader2 className="animate-spin text-slate-400" size={16} />
          </div>
        )}
      </div>
      {showSuggestions && suggestions.length > 0 && (
        <ul className="absolute z-50 w-full bg-white border border-slate-200 rounded-md shadow-lg mt-1 max-h-60 overflow-y-auto">
          {suggestions.map((feature: any, index: number) => (
            <li 
              key={index}
              onClick={() => handleSelectSuggestion(feature)}
              className="px-4 py-2 hover:bg-indigo-50 cursor-pointer text-sm border-b border-slate-50 last:border-0"
            >
              <p className="font-medium text-slate-800">{feature.properties.address_line1}</p>
              <p className="text-xs text-slate-500">{feature.properties.address_line2}</p>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export const AddressForm: React.FC<AddressFormProps> = ({ 
  initialData, 
  type, 
  onSave, 
  onCancel, 
  enableSaveOption = false 
}) => {
  const [address, setAddress] = useState<Partial<Address>>({
    country: 'US',
    type: type,
    ...initialData
  });

  const [saveToBook, setSaveToBook] = useState(true);
  const [showEmailError, setShowEmailError] = useState(false);

  // Custom email validation function (no AI used)
  const isValidEmail = (email: string) => {
    // Standard basic email regex
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setShowEmailError(false);

    if (!address.name || !address.street1 || !address.city || !address.state || !address.zip || !address.phone || !address.email) {
      alert("Please fill in all required fields.");
      return;
    }

    if (!isValidEmail(address.email)) {
      setShowEmailError(true);
      return;
    }

    const finalAddress: Address = {
      id: address.id || `addr_${Date.now()}`,
      name: address.name || '',
      company: address.company || '',
      street1: address.street1 || '',
      street2: address.street2 || '',
      city: address.city || '',
      state: address.state || '',
      zip: address.zip || '',
      country: address.country || 'US',
      phone: address.phone || '',
      email: address.email || '',
      type: type
    };

    onSave(finalAddress, saveToBook);
  };

  const handleAddressSelect = (data: any) => {
    setAddress(prev => ({
      ...prev,
      street1: data.street1,
      city: data.city,
      state: data.state,
      zip: data.zip,
      country: data.country
    }));
  };

  return (
    <div className="flex flex-col h-full w-full overflow-hidden">
      <div className="bg-slate-900 text-white p-6 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-600 rounded-lg">
            <User size={24} className="text-white" />
          </div>
          <div>
            <h2 className="text-xl font-bold">
              {initialData?.id ? 'Edit Contact' : 'Add New Contact'}
            </h2>
            <p className="text-slate-400 text-sm">
              {type === 'SENDER' ? 'Origin Details' : 'Destination Details'}
            </p>
          </div>
        </div>
        <button onClick={onCancel} className="text-slate-400 hover:text-white transition-colors">
          <X size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-6 min-h-0">
        <div className="space-y-6">
          {showEmailError && (
             <div className="p-3 bg-red-50 border border-red-200 rounded-lg flex items-center gap-3 animate-pulse">
                <AlertCircle className="text-red-600" size={20} />
                <div>
                   <p className="text-sm font-medium text-red-800">Invalid Email Address</p>
                   <p className="text-xs text-red-600">Please correct the email address to continue.</p>
                </div>
             </div>
          )}

          {/* Section: Identity */}
          <div>
            <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider border-b pb-2 mb-4 flex items-center gap-2">
              <User size={16} /> Identity
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <InputField 
                label="Contact Name" 
                value={address.name} 
                onChange={(e: any) => setAddress({...address, name: e.target.value})}
                placeholder="e.g. John Doe" 
                required={true} 
              />
              <InputField 
                label="Company Name" 
                value={address.company} 
                onChange={(e: any) => setAddress({...address, company: e.target.value})}
                placeholder="e.g. Acme Inc." 
              />
            </div>
          </div>

          {/* Section: Address */}
          <div>
            <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider border-b pb-2 mb-4 flex items-center gap-2">
              <Building size={16} /> Address
            </h3>
            <div className="grid grid-cols-1 gap-4">
              <AddressAutocomplete 
                label="Street Address" 
                value={address.street1} 
                onChange={(e: any) => setAddress({...address, street1: e.target.value})}
                onSelect={handleAddressSelect}
                placeholder="Type to search address..." 
                required={true} 
              />
              <InputField 
                label="Apt / Suite / Unit" 
                value={address.street2} 
                onChange={(e: any) => setAddress({...address, street2: e.target.value})}
                placeholder="Suite 400" 
              />

              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="col-span-2">
                  <InputField 
                    label="City" 
                    value={address.city} 
                    onChange={(e: any) => setAddress({...address, city: e.target.value})}
                    placeholder="New York" 
                    required={true} 
                  />
                </div>
                <InputField 
                  label="State" 
                  value={address.state} 
                  onChange={(e: any) => setAddress({...address, state: e.target.value})}
                  placeholder="NY" 
                  required={true} 
                />
                <InputField 
                  label="Zip Code" 
                  value={address.zip} 
                  onChange={(e: any) => setAddress({...address, zip: e.target.value})}
                  placeholder="10001" 
                  required={true} 
                />
              </div>
              <InputField 
                label="Country" 
                value={address.country} 
                onChange={(e: any) => setAddress({...address, country: e.target.value})}
                placeholder="US" 
              />
            </div>
          </div>

          {/* Section: Contact */}
          <div>
            <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider border-b pb-2 mb-4 flex items-center gap-2">
              <Phone size={16} /> Contact Info
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="relative">
                <InputField 
                  label="Email Address" 
                  value={address.email} 
                  onChange={(e: any) => {
                     setAddress({...address, email: e.target.value});
                     if (showEmailError) setShowEmailError(false);
                  }}
                  placeholder="john@example.com" 
                  type="email" 
                  required={true}
                />
                <Mail className="absolute right-3 top-9 text-slate-400" size={16} />
              </div>
              <div className="relative">
                  <InputField 
                  label="Phone Number" 
                  value={address.phone} 
                  onChange={(e: any) => setAddress({...address, phone: e.target.value})}
                  placeholder="(555) 123-4567" 
                  type="tel" 
                  required={true}
                  />
                  <Phone className="absolute right-3 top-9 text-slate-400" size={16} />
              </div>
            </div>
          </div>

          {enableSaveOption && (
            <div className="pt-4 border-t border-slate-100">
               <label className="flex items-center gap-3 p-4 border border-indigo-100 bg-indigo-50/50 rounded-lg cursor-pointer hover:bg-indigo-50 transition-colors">
                  <input 
                    type="checkbox" 
                    checked={saveToBook}
                    onChange={(e) => setSaveToBook(e.target.checked)}
                    className="w-5 h-5 text-indigo-600 rounded focus:ring-indigo-500" 
                  />
                  <div>
                    <span className="font-medium text-slate-900">Save to Address Book</span>
                    <p className="text-xs text-slate-500">Save this contact for future shipments</p>
                  </div>
                </label>
            </div>
          )}

        </div>
      </form>

      <div className="bg-slate-50 p-6 border-t border-slate-200 flex justify-end gap-3 shrink-0">
        <button 
          type="button" 
          onClick={onCancel}
          className="px-5 py-2.5 rounded-lg text-slate-700 hover:bg-slate-200 font-medium transition-colors"
        >
          Cancel
        </button>
        <button 
          onClick={handleSubmit}
          className="px-6 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-medium shadow-lg shadow-indigo-200 flex items-center gap-2 transition-all"
        >
          <Save size={20} />
          {initialData?.id ? 'Update Contact' : 'Save Contact'}
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ViewState, Address, Shipment } from './types';
import { AddressBook } from './components/AddressBook';
import { ShipmentHistory } from './components/ShipmentHistory';
import { CreateLabelModal } from './components/CreateLabelModal';
import { Settings } from './components/Settings';
import { MOCK_RECIPIENTS, MOCK_SENDERS } from './constants';
import { 
  LayoutDashboard, 
  Package, 
  Users, 
  Settings as SettingsIcon, 
  LogOut, 
  Box, 
  Bell 
} from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('SHIPMENTS');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedRecipient, setSelectedRecipient] = useState<Address | null>(null);
  const [notification, setNotification] = useState<string | null>(null);

  // Address State with LocalStorage Persistence
  const [recipients, setRecipients] = useState<Address[]>(() => {
    const saved = localStorage.getItem('fedex_recipients');
    return saved ? JSON.parse(saved) : MOCK_RECIPIENTS;
  });

  const [senders, setSenders] = useState<Address[]>(() => {
    const saved = localStorage.getItem('fedex_senders');
    return saved ? JSON.parse(saved) : MOCK_SENDERS;
  });

  // Save to LocalStorage whenever state changes
  useEffect(() => {
    localStorage.setItem('fedex_recipients', JSON.stringify(recipients));
  }, [recipients]);

  useEffect(() => {
    localStorage.setItem('fedex_senders', JSON.stringify(senders));
  }, [senders]);

  const handleGenerateLabel = (recipient: Address | null = null) => {
    setSelectedRecipient(recipient);
    setIsModalOpen(true);
  };

  const handleLabelSuccess = (shipment: Shipment) => {
    setNotification(`Label created successfully! Tracking: ${shipment.trackingNumber}`);
    setTimeout(() => setNotification(null), 5000);
    setView('SHIPMENTS'); // Redirect to history to see new label
  };

  const SidebarItem = ({ id, icon: Icon, label }: { id: ViewState, icon: any, label: string }) => (
    <button
      onClick={() => setView(id)}
      className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium transition-colors rounded-lg mb-1 ${
        view === id 
          ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' 
          : 'text-slate-400 hover:text-white hover:bg-slate-800'
      }`}
    >
      <Icon size={20} />
      {label}
    </button>
  );

  return (
    <div className="min-h-screen flex bg-slate-50">

      {/* Sidebar */}
      <aside className="fixed inset-y-0 left-0 w-64 bg-slate-900 text-white z-20 flex flex-col">
        <div className="p-6 flex items-center gap-3 border-b border-slate-800">
          <div className="bg-gradient-to-br from-indigo-500 to-purple-600 p-2 rounded-lg">
            <Box size={24} className="text-white" />
          </div>
          <div>
            <h1 className="font-bold text-lg tracking-tight">ShipMaster</h1>
            <p className="text-xs text-slate-400">FedEx Enterprise</p>
          </div>
        </div>

        <nav className="flex-1 p-4">
          <p className="px-4 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-4 mt-2">Menu</p>
          <SidebarItem id="DASHBOARD" icon={LayoutDashboard} label="Dashboard" />
          <SidebarItem id="SHIPMENTS" icon={Package} label="Shipments" />
          <SidebarItem id="ADDRESS_BOOK" icon={Users} label="Address Book" />
          <SidebarItem id="SETTINGS" icon={SettingsIcon} label="Settings" />
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center gap-3 px-4 py-3 mb-2">
            <div className="h-8 w-8 rounded-full bg-indigo-500 flex items-center justify-center font-bold text-xs">
              JD
            </div>
            <div className="overflow-hidden">
              <p className="text-sm font-medium truncate">John Doe</p>
              <p className="text-xs text-slate-500 truncate">Ops Manager</p>
            </div>
          </div>
          <button className="w-full flex items-center gap-3 px-4 py-2 text-sm text-slate-400 hover:text-white transition-colors">
            <LogOut size={18} />
            Sign Out
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="ml-64 flex-1 min-h-screen flex flex-col">

        {/* Top Header */}
        <header className="h-16 bg-white border-b border-slate-200 sticky top-0 z-10 px-8 flex items-center justify-between">
          <h2 className="text-lg font-semibold text-slate-700">
            {view === 'DASHBOARD' && 'Overview'}
            {view === 'SHIPMENTS' && 'Shipment Management'}
            {view === 'ADDRESS_BOOK' && 'Contact Management'}
            {view === 'SETTINGS' && 'System Settings'}
          </h2>

          <div className="flex items-center gap-4">
             <button 
              onClick={() => handleGenerateLabel(null)}
              className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium shadow-sm transition-all flex items-center gap-2"
            >
              <Box size={16} />
              Quick Label
            </button>
            <div className="relative">
              <Bell size={20} className="text-slate-400 hover:text-slate-600 cursor-pointer" />
              <span className="absolute -top-1 -right-1 h-2.5 w-2.5 bg-red-500 rounded-full border-2 border-white"></span>
            </div>
          </div>
        </header>

        {/* Content Area */}
        <div className="p-8">
          {notification && (
            <div className="mb-6 p-4 bg-green-50 border border-green-200 text-green-700 rounded-lg flex items-center justify-between animate-fade-in-down shadow-sm">
              <div className="flex items-center gap-2">
                <Box size={20} />
                <span className="font-medium">{notification}</span>
              </div>
              <button onClick={() => setNotification(null)} className="text-green-600 hover:text-green-800 font-bold">×</button>
            </div>
          )}

          {view === 'DASHBOARD' && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                <p className="text-sm text-slate-500 font-medium">Total Shipments</p>
                <p className="text-3xl font-bold text-slate-900 mt-2">1,284</p>
                <p className="text-xs text-green-600 mt-1 flex items-center">↑ 12% vs last month</p>
              </div>
              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                <p className="text-sm text-slate-500 font-medium">In Transit</p>
                <p className="text-3xl font-bold text-indigo-600 mt-2">42</p>
                <p className="text-xs text-slate-400 mt-1">Updates every 15 min</p>
              </div>
              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                <p className="text-sm text-slate-500 font-medium">Exceptions</p>
                <p className="text-3xl font-bold text-red-600 mt-2">3</p>
                <p className="text-xs text-slate-400 mt-1">Requires attention</p>
              </div>

              <div className="col-span-3 mt-4">
                 <ShipmentHistory />
              </div>
            </div>
          )}

          {view === 'SHIPMENTS' && <ShipmentHistory />}

          {view === 'ADDRESS_BOOK' && (
            <AddressBook 
              onGenerateLabel={handleGenerateLabel} 
              recipients={recipients}
              senders={senders}
              onUpdateRecipients={setRecipients}
              onUpdateSenders={setSenders}
            />
          )}

          {view === 'SETTINGS' && (
             <Settings />
          )}
        </div>
      </main>

      <CreateLabelModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)}
        preSelectedRecipient={selectedRecipient}
        onSuccess={handleLabelSuccess}
        recipients={recipients}
        senders={senders}
        onAddRecipient={(addr) => setRecipients([addr, ...recipients])}
        onAddSender={(addr) => setSenders([addr, ...senders])}
      />
    </div>
  );
};

export default App;

