import { LabelGenerationRequest, Shipment, ShipmentStatus } from '../types';
import { MOCK_SENDERS, MOCK_RECIPIENTS } from '../constants';
import { settingsService } from './settingsService';

const LOCAL_STORAGE_KEY = 'fedex_app_shipments';

const getStoredShipments = (): Shipment[] => {
  const stored = localStorage.getItem(LOCAL_STORAGE_KEY);
  return stored ? JSON.parse(stored) : [];
};

const saveShipment = (shipment: Shipment) => {
  const current = getStoredShipments();
  localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify([shipment, ...current]));
};

export const n8nService = {
  createLabel: async (request: LabelGenerationRequest): Promise<Shipment> => {
    const settings = settingsService.getSettings();

    // If a webhook URL is provided, try to use it
    if (settings.n8nWebhookUrl && settings.n8nWebhookUrl.trim() !== '') {
      try {
        const response = await fetch(settings.n8nWebhookUrl, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(request),
        });

        if (!response.ok) {
          let errorBody = '';
          try {
            errorBody = await response.text();
          } catch (e) {
            // ignore JSON parsing error
          }
          throw new Error(`Server returned ${response.status} ${response.statusText}. Details: ${errorBody.substring(0, 200)}`);
        }

        const data = await response.json();

        // Ensure the response maps to our Shipment type
        // Assuming the webhook returns the full shipment object
        const shipment: Shipment = {
           ...data,
           // Ensure dates are strings if not already
           createdDate: data.createdDate || new Date().toISOString(),
           status: data.status || ShipmentStatus.CREATED
        };

        saveShipment(shipment);
        return shipment;
      } catch (error: any) {
        console.error("N8N Webhook Error:", error);

        // If it's the default placeholder, ignore and fall back to mock
        if (settings.n8nWebhookUrl.includes('yourdomain.com')) {
           console.warn("Using placeholder URL, falling back to mock data.");
        } else {
           // Re-throw so the UI can display the specific error
           throw error;
        }
      }
    }

    // --- MOCK FALLBACK (If no URL configured) ---
    await new Promise(resolve => setTimeout(resolve, 1500));

    const sender = MOCK_SENDERS.find(s => s.id === request.senderId) || MOCK_SENDERS[0];
    const recipient = MOCK_RECIPIENTS.find(r => r.id === request.recipientId) || MOCK_RECIPIENTS[0];

    // Mock Response from N8N
    const newShipment: Shipment = {
      id: `shp_${Date.now()}`,
      trackingNumber: `1234${Math.floor(Math.random() * 100000000)}`, // Mock Tracking
      reference: request.reference,
      status: ShipmentStatus.CREATED,
      createdDate: new Date().toISOString(),
      sender,
      recipient,
      serviceType: request.serviceType,
      packageType: request.packageType,
      weight: request.weight,
      isReturnLabel: request.options.createReturnLabel,
      notifications: request.options.notifyEmails,
      labelUrl: 'https://dummyimage.com/600x800/fff/000.png&text=FEDEX+LABEL+SAMPLE',
      price: Math.floor(Math.random() * 60) + 15.50 // Mock price between 15.50 and 75.50
    };

    saveShipment(newShipment);
    return newShipment;
  },

  getHistory: async (): Promise<Shipment[]> => {
    // Simulate Network Latency
    await new Promise(resolve => setTimeout(resolve, 500));
    return getStoredShipments();
  },

  // This would typically trigger a webhook to refresh status
  refreshTracking: async (trackingNumber: string): Promise<ShipmentStatus> => {
    await new Promise(resolve => setTimeout(resolve, 1000));
    const statuses = Object.values(ShipmentStatus);
    const randomStatus = statuses[Math.floor(Math.random() * statuses.length)];
    return randomStatus;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { X, Truck, Save, Loader2, AlertCircle, Plus, ChevronDown, Search } from 'lucide-react';
import { Address, LabelGenerationRequest, Shipment } from '../types';
import { SERVICE_TYPES, PACKAGE_TYPES, INTERNAL_USERS } from '../constants';
import { n8nService } from '../services/n8nService';
import { AddressForm } from './AddressForm';

interface CreateLabelModalProps {
  isOpen: boolean;
  onClose: () => void;
  preSelectedRecipient?: Address | null;
  onSuccess: (shipment: Shipment) => void;
  recipients: Address[];
  senders: Address[];
  onAddRecipient: (addr: Address) => void;
  onAddSender: (addr: Address) => void;
}

// Searchable Dropdown Component
const SearchableAddressSelect = ({ 
  label, 
  value, 
  onChange, 
  options, 
  onAddNew, 
  placeholder 
}: {
  label: string;
  value: string;
  onChange: (val: string) => void;
  options: Address[];
  onAddNew: () => void;
  placeholder: string;
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const wrapperRef = useRef<HTMLDivElement>(null);

  const selectedOption = options.find((o) => o.id === value);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const filteredOptions = options.filter((opt) => 
    opt.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (opt.company && opt.company.toLowerCase().includes(searchTerm.toLowerCase())) ||
    opt.city.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="relative" ref={wrapperRef}>
       <div className="flex justify-between items-center mb-1">
        <label className="block text-sm font-medium text-slate-700">{label}</label>
        <button 
            type="button" 
            onClick={onAddNew}
            className="text-xs text-indigo-600 hover:text-indigo-800 flex items-center gap-1 font-medium bg-indigo-50 px-2 py-1 rounded hover:bg-indigo-100 transition-colors"
        >
            <Plus size={12} /> New
        </button>
      </div>

      <div 
        className="relative cursor-pointer"
        onClick={() => {
            if (!isOpen) {
                setIsOpen(true);
                setSearchTerm(''); 
            } else {
                setIsOpen(false);
            }
        }}
      >
        <div className={`w-full rounded-md border border-slate-300 p-2.5 bg-white flex items-center justify-between shadow-sm hover:border-indigo-400 transition-colors ${isOpen ? 'ring-2 ring-indigo-500 border-indigo-500' : ''}`}>
            <span className={`block truncate ${selectedOption ? 'text-slate-700' : 'text-slate-400'}`}>
                {selectedOption 
                    ? `${selectedOption.name} ${selectedOption.company ? `(${selectedOption.company})` : ''} - ${selectedOption.city}, ${selectedOption.state}` 
                    : placeholder}
            </span>
            <ChevronDown size={16} className="text-slate-400" />
        </div>
      </div>

      {isOpen && (
        <div className="absolute z-20 w-full bg-white border border-slate-200 rounded-md shadow-lg mt-1 max-h-60 overflow-y-auto">
          <div className="p-2 sticky top-0 bg-white border-b border-slate-100" onClick={(e) => e.stopPropagation()}>
             <div className="relative">
                <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"/>
                <input 
                    autoFocus
                    type="text"
                    className="w-full pl-9 pr-3 py-2 text-sm border border-slate-200 rounded-md focus:outline-none focus:border-indigo-500 bg-slate-50"
                    placeholder="Search name, company, city..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
             </div>
          </div>
          {filteredOptions.length === 0 ? (
             <div className="p-3 text-sm text-slate-500 text-center">No results found</div>
          ) : (
             filteredOptions.map((opt) => (
                <div 
                    key={opt.id}
                    onClick={() => {
                        onChange(opt.id);
                        setIsOpen(false);
                        setSearchTerm('');
                    }}
                    className={`px-4 py-2 hover:bg-indigo-50 cursor-pointer text-sm border-b border-slate-50 last:border-0 ${opt.id === value ? 'bg-indigo-50 text-indigo-700' : 'text-slate-700'}`}
                >
                    <div className="font-medium">{opt.name} {opt.company && <span className="text-slate-500 font-normal">({opt.company})</span>}</div>
                    <div className="text-xs text-slate-500">{opt.street1}, {opt.city}, {opt.state}</div>
                </div>
             ))
          )}
        </div>
      )}
    </div>
  );
};

