      try {
        console.log("Sending payload to N8N:", webhookPayload);

        const response = await fetch(cleanUrl, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Accept': 'application/json'
          },
          credentials: 'omit', // IMPORTANT: Added to match working sample from user
          body: JSON.stringify(webhookPayload),
        });

        if (!response.ok) {
          // Try to get detailed JSON error from N8N (it usually returns { code, message })
          let errorBody = response.statusText;
          try {
             const errorJson = await response.json();
             if (errorJson.message) {
                 errorBody = errorJson.message;
                 // If there's a stack or data, maybe log it but don't show user everything
                 if (errorJson.data) console.error("N8N Error Data:", errorJson.data);
