          }

          throw new Error(`Webhook Failed (${response.status}): ${errorBody.substring(0, 300)}`);
        }

        const data = await response.json();

        const shipment: Shipment = {
           id: data.id || `shp_${Date.now()}`,
           trackingNumber: data.trackingNumber || 'UNKNOWN',
           reference: data.reference || request.reference,
           status: data.status || ShipmentStatus.CREATED,
           createdDate: data.createdDate || new Date().toISOString(),
